arguments.argument:
if global.gamePaused=false
{
  image_angle+=30
  if atkProg=0
  {
    x=warTarget.x
    y=warTarget.y-27
  }
  else if atkProg=1
  {
    atkTime+=1
    if atkTime=1
    {
      direction=point_direction(x,y,oPlayer1.x,returnPlayerYCenter())      
    }
    else {speed=5}
  }
}
else {speed=0}
